import React from 'react';
import TaskCard from './TaskCard';

const TaskList = ({ tasks, users, projects, onStatusChange }) => {
  const handleStatusChange = (taskId, newStatus) => {
    if (onStatusChange) {
      onStatusChange(taskId, newStatus);
    }
  };

  if (tasks.length === 0) {
    return (
      <div className="empty-state">
        <p>No tasks found. Create your first task to get started!</p>
      </div>
    );
  }

  // Get assignee and project details for each task
  const tasksWithDetails = tasks.map(task => {
    const assignee = users?.find(user => user.id === task.assignee_id);
    const project = projects?.find(proj => proj.id === task.project_id);

    return {
      ...task,
      assignee_name: assignee?.name || 'Unassigned',
      project_name: project?.name || 'No Project',
      project_color: project?.color || '#cccccc'
    };
  });

  return (
    <div className="task-list">
      {tasksWithDetails.map(task => (
        <TaskCard 
          key={task.id} 
          task={task} 
          onStatusChange={handleStatusChange}
        />
      ))}
    </div>
  );
};

export default TaskList;
